    SalesLine               salesLine;

    select firstonly salesLine
        where salesLine.SalesId == 'PV2300229';

    SalesFormLetter_PackingSlip salesFormLetter_PackingSlip = salesFormLetter::construct(DocumentStatus::PackingSlip);
    Query               query = new Query(queryStr(SalesUpdate));

    query.dataSourceTable(tablenum(SalesLine)).addRange(fieldnum(SalesLine, RecId)).value(queryValue(salesLine.RecId));

    SysQueryRun queryRun = new SysQueryRun(query);

    salesFormLetter_PackingSlip.chooseLinesQuery(queryRun);
    salesFormLetter_PackingSlip.transDate(today());
    salesFormLetter_PackingSlip.specQty(SalesUpdate::PickingList);
    salesFormLetter_PackingSlip.printFormLetter(false);
    salesFormLetter_PackingSlip.chooseLines();
    salesFormLetter_PackingSlip.sumBy(AccountOrder::Account);
    salesFormLetter_PackingSlip.reArrangeNow(true);
    salesFormLetter_PackingSlip.proforma(false);

    salesFormLetter_PackingSlip.run();
}
